1	.page { padding: 24rpx; }
2	.page-header { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 32rpx; }
3	.page-title { font-size: 48rpx; font-weight: bold; display: block; }
4	.page-subtitle { font-size: 24rpx; color: #78716c; display: block; margin-top: 4rpx; }
5	.add-btn { width: 72rpx; height: 72rpx; border-radius: 50%; background: #1c1917; color: #fff; display: flex; align-items: center; justify-content: center; font-size: 40rpx; }
6	.domain-title { font-size: 26rpx; color: #78716c; margin: 28rpx 0 14rpx; display: block; }
7	.habit-card { background: #fff; border-radius: 20rpx; padding: 28rpx; margin-bottom: 12rpx; box-shadow: 0 2rpx 12rpx rgba(0,0,0,0.03); }
8	.habit-card.inactive { opacity: 0.4; }
9	.habit-info { margin-bottom: 16rpx; }
10	.habit-name { font-size: 30rpx; font-weight: 500; display: block; }
11	.habit-desc { font-size: 22rpx; color: #78716c; display: block; margin-top: 4rpx; }
12	.habit-meta { font-size: 22rpx; color: #a8a29e; margin-top: 8rpx; display: block; }
13	.habit-actions { display: flex; gap: 16rpx; }
14	.action-btn { font-size: 24rpx; padding: 8rpx 20rpx; border-radius: 12rpx; background: #f5f3f0; color: #1c1917; }
15	.action-btn.danger { background: #fef2f2; color: #ef4444; }
16	.empty { text-align: center; padding: 80rpx 0; color: #a8a29e; }
17	.modal-mask { position: fixed; top: 0; left: 0; right: 0; bottom: 0; background: rgba(0,0,0,0.4); z-index: 100; display: flex; align-items: center; justify-content: center; }
18	.modal { background: #fff; width: 630rpx; border-radius: 32rpx; padding: 40rpx; max-height: 80vh; overflow: auto; }
19	.modal-title { font-size: 36rpx; font-weight: bold; display: block; margin-bottom: 28rpx; }
20	.form-group { margin-bottom: 20rpx; }
21	.form-label { font-size: 26rpx; font-weight: 500; display: block; margin-bottom: 8rpx; }
22	.form-input { width: 100%; height: 76rpx; border-radius: 16rpx; background: #f5f3f0; padding: 0 24rpx; font-size: 28rpx; box-sizing: border-box; }
23	.form-picker { width: 100%; height: 76rpx; border-radius: 16rpx; background: #f5f3f0; padding: 0 24rpx; font-size: 28rpx; display: flex; align-items: center; box-sizing: border-box; }
24	.form-row { display: flex; gap: 20rpx; }
25	.flex-1 { flex: 1; }
26	.form-buttons { display: flex; gap: 20rpx; margin-top: 32rpx; }
27	.btn-cancel { flex: 1; height: 80rpx; border-radius: 20rpx; border: 2rpx solid #e0dcd5; display: flex; align-items: center; justify-content: center; font-size: 30rpx; }
28	.btn-save { flex: 1; height: 80rpx; border-radius: 20rpx; background: #1c1917; display: flex; align-items: center; justify-content: center; font-size: 30rpx; color: #fff; }
29

1	export function getToday(): string {
2	  return new Date().toISOString().split("T")[0];
3	}
4	
5	export function formatDate(date: Date | string): string {
6	  return new Date(date).toLocaleDateString("zh-CN", {
7	    year: "numeric",
8	    month: "long",
9	    day: "numeric",
10	    weekday: "long",
11	  });
12	}
13	
14	export const PRESET_DOMAINS = [
15	  { name: "健身", icon: "💪", color: "#ef4444" },
16	  { name: "读书", icon: "📚", color: "#3b82f6" },
17	  { name: "变美", icon: "✨", color: "#ec4899" },
18	  { name: "工作", icon: "💼", color: "#f59e0b" },
19	  { name: "学习", icon: "🧠", color: "#8b5cf6" },
20	  { name: "商业思维", icon: "🏛️", color: "#10b981" },
21	  { name: "视野", icon: "🌍", color: "#06b6d4" },
22	  { name: "生活习惯", icon: "🏠", color: "#78716c" },
23	];
